 1	import React, { FC, useState } from 'react';
 2	import { useNavigate } from 'react-router-dom-v5-compat';
 3	
 4	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
 5	import { isEmpty, kubevirtConsole } from '@kubevirt-utils/utils/utils';
 6	import { useActiveNamespace } from '@openshift-console/dynamic-plugin-sdk';
 7	import { ActionGroup, Alert, AlertVariant, Button, ButtonVariant } from '@patternfly/react-core';
 8	
 9	import { createStorageCheckup } from '../../utils/utils';
10	
11	type CheckupsStorageFormActionsProps = {
12	  name: string;
13	  timeOut: string;
14	};
15	
16	const CheckupsStorageFormActions: FC<CheckupsStorageFormActionsProps> = ({ name, timeOut }) => {
17	  const { t } = useKubevirtTranslation();
18	  const navigate = useNavigate();
19	  const [namespace] = useActiveNamespace();
20	  const [error, setError] = useState<string>(null);
21	
22	  return (
23	    <>
24	      <ActionGroup>
25	        <Button
26	          onClick={async () => {
27	            setError(null);
28	            try {
29	              await createStorageCheckup(namespace, timeOut, name);
30	              navigate(`/k8s/ns/${namespace}/checkups/storage`);
31	            } catch (e) {
32	              kubevirtConsole.log(e);
33	              setError(e?.message);
34	            }
35	          }}
36	          isDisabled={isEmpty(name) || isEmpty(timeOut)}
37	          variant={ButtonVariant.primary}
38	        >
39	          {t('Run')}
40	        </Button>
41	        <Button onClick={() => navigate(-1)} variant={ButtonVariant.secondary}>
42	          {t('Cancel')}
43	        </Button>
44	      </ActionGroup>
45	      {error && (
46	        <Alert title={t('Failed to create resource')} variant={AlertVariant.danger}>
47	          {error}
48	        </Alert>
49	      )}
50	    </>
51	  );
52	};
53	
54	export default CheckupsStorageFormActions;

